"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import axios from "axios";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Checkbox } from "@/components/ui/checkbox";
import { motion } from "framer-motion";
import { Eye, EyeOff, Mail, Lock, Heart, Sparkles } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import Image from "next/image";
import logo from "@/assets/logo.png";

const FloatingEmojis = () => (
  <>
    <motion.div animate={{ y: [0, -15, 0], rotate: [0, 5, 0] }} transition={{ duration: 6, repeat: Infinity, ease: "easeInOut" }} className="absolute top-[10%] left-[8%] text-4xl select-none">🧘</motion.div>
    <motion.div animate={{ y: [0, 12, 0], rotate: [0, -8, 0] }} transition={{ duration: 5, repeat: Infinity, ease: "easeInOut", delay: 1 }} className="absolute top-[15%] right-[12%] text-3xl select-none">🌸</motion.div>
    <motion.div animate={{ y: [0, -10, 0] }} transition={{ duration: 7, repeat: Infinity, ease: "easeInOut", delay: 2 }} className="absolute bottom-[20%] left-[15%] text-3xl select-none">🍃</motion.div>
    <motion.div animate={{ y: [0, 10, 0], x: [0, 5, 0] }} transition={{ duration: 4, repeat: Infinity, ease: "easeInOut", delay: 0.5 }} className="absolute bottom-[25%] right-[10%] text-2xl select-none">✨</motion.div>
    <motion.div animate={{ y: [0, -8, 0] }} transition={{ duration: 5.5, repeat: Infinity, ease: "easeInOut", delay: 3 }} className="absolute top-[40%] left-[5%] text-2xl select-none">💜</motion.div>
    <motion.div animate={{ scale: [1, 1.1, 1], rotate: [0, 10, 0] }} transition={{ duration: 8, repeat: Infinity, ease: "easeInOut" }} className="absolute top-[8%] left-[45%] text-3xl select-none">🦋</motion.div>
  </>
);

export default function LoginPage() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [remember, setRemember] = useState(false);
  const { toast } = useToast();
  const router = useRouter();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const response = await axios.post("http://localhost:5000/api/auth/login", {
        email,
        password,
      });

      if (response.data.success) {
        localStorage.setItem("token", response.data.token);
        toast({ title: "Welcome back! 🌿", description: "Redirecting to your dashboard..." });
        router.push("/app");
      }
    } catch (err: any) {
      toast({
        title: "Login failed",
        description: err.response?.data?.message || "Please check your credentials.",
        variant: "destructive",
      });
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center relative overflow-hidden px-4 py-8"
      style={{ background: "linear-gradient(135deg, hsl(180, 40%, 85%) 0%, hsl(200, 50%, 88%) 25%, hsl(280, 30%, 90%) 50%, hsl(330, 40%, 90%) 75%, hsl(30, 50%, 90%) 100%)" }}
    >
      <FloatingEmojis />

      {/* Gradient orbs */}
      <div className="absolute top-[-10%] right-[-5%] w-72 h-72 rounded-full opacity-40" style={{ background: "radial-gradient(circle, hsl(280, 60%, 80%), transparent)" }} />
      <div className="absolute bottom-[-10%] left-[-5%] w-80 h-80 rounded-full opacity-30" style={{ background: "radial-gradient(circle, hsl(170, 60%, 75%), transparent)" }} />

      <motion.div initial={{ opacity: 0, y: 30, scale: 0.95 }} animate={{ opacity: 1, y: 0, scale: 1 }} transition={{ duration: 0.6 }} className="w-full max-w-md relative">
        {/* Glowing border */}
        <div className="absolute -inset-[2px] rounded-3xl opacity-60" style={{ background: "linear-gradient(135deg, hsl(170, 60%, 65%), hsl(280, 50%, 75%), hsl(330, 50%, 75%))" }} />

        <div className="relative rounded-3xl p-8 space-y-6" style={{ background: "hsla(0, 0%, 100%, 0.75)", backdropFilter: "blur(20px)", boxShadow: "0 20px 60px -15px hsla(280, 40%, 50%, 0.2), inset 0 1px 0 hsla(0, 0%, 100%, 0.6)" }}>
          {/* Header */}
          <div className="text-center space-y-3">
            <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ type: "spring", stiffness: 200, delay: 0.2 }} className="mx-auto w-20 h-20 rounded-full flex items-center justify-center shadow-lg" style={{ background: "linear-gradient(135deg, hsl(var(--primary)), hsl(170, 60%, 50%))" }}>
              <Image src={logo} alt="Sentira" width={48} height={48} className="object-contain" />
            </motion.div>
            <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-body font-medium" style={{ background: "hsl(var(--accent))", color: "hsl(var(--accent-foreground))" }}>
              <Sparkles className="w-3 h-3" />
              Welcome Back, Friend!
            </div>
            <h1 className="font-display text-2xl font-bold text-foreground">LOGIN</h1>
            <p className="font-body text-sm text-muted-foreground">Continue your wellness journey</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-1.5">
              <Label htmlFor="email" className="font-body text-sm font-semibold text-foreground">Email Address</Label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input id="email" type="email" placeholder="you@example.com" value={email} onChange={(e) => setEmail(e.target.value)} className="font-body py-5 pl-10 rounded-xl border-border/50" style={{ background: "hsla(0, 0%, 100%, 0.6)" }} required />
              </div>
            </div>

            <div className="space-y-1.5">
              <Label htmlFor="password" className="font-body text-sm font-semibold text-foreground">Password</Label>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input id="password" type={showPassword ? "text" : "password"} placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} className="pl-10 pr-10 font-body py-5 rounded-xl border-border/50" style={{ background: "hsla(0, 0%, 100%, 0.6)" }} required />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors">
                  {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </button>
              </div>
            </div>

            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Checkbox id="remember" checked={remember} onCheckedChange={(v) => setRemember(v as boolean)} />
                <Label htmlFor="remember" className="font-body text-sm text-muted-foreground cursor-pointer">Remember me</Label>
              </div>
              <a href="#" className="font-body text-sm font-semibold text-primary hover:underline">Forgot password?</a>
            </div>

            <Button type="submit" className="w-full rounded-xl font-body font-semibold py-5 text-base text-primary-foreground shadow-lg" style={{ background: "linear-gradient(135deg, hsl(var(--primary)), hsl(170, 50%, 45%))", boxShadow: "0 8px 25px -5px hsla(161, 93%, 30%, 0.4)" }}>
              <Heart className="w-4 h-4 mr-2" />
              Log In
            </Button>
          </form>

          {/* Divider */}
          <div className="flex items-center gap-3">
            <div className="flex-1 h-px bg-border/50" />
            <span className="font-body text-xs text-muted-foreground uppercase">or continue with</span>
            <div className="flex-1 h-px bg-border/50" />
          </div>

          {/* Social */}
          <div className="flex gap-3">
            <Button variant="outline" className="flex-1 rounded-xl font-body gap-2 py-5 border-border/50" style={{ background: "hsla(0, 0%, 100%, 0.5)" }}>
              <svg className="w-4 h-4" viewBox="0 0 24 24"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4" /><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" /><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" /><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" /></svg>
              Google
            </Button>
            <Button variant="outline" className="flex-1 rounded-xl font-body gap-2 py-5 border-border/50" style={{ background: "hsla(0, 0%, 100%, 0.5)" }}>
              <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M17.05 20.28c-.98.95-2.05.88-3.08.4-1.09-.5-2.08-.48-3.24 0-1.44.62-2.2.44-3.06-.4C2.79 15.25 3.51 7.59 9.05 7.31c1.35.07 2.29.74 3.08.8 1.18-.24 2.31-.93 3.57-.84 1.51.12 2.65.72 3.4 1.8-3.12 1.87-2.38 5.98.48 7.13-.57 1.5-1.31 2.99-2.54 4.09zM12.03 7.25c-.15-2.23 1.66-4.07 3.74-4.25.32 2.32-1.55 4.16-3.74 4.25z" /></svg>
              Apple
            </Button>
          </div>

          <p className="font-body text-sm text-muted-foreground text-center">
            Don't have an account?{" "}
            <Link href="/register" className="text-primary font-semibold hover:underline">Sign up</Link>
          </p>
          <Link href="/" className="block text-center font-body text-xs text-muted-foreground hover:text-foreground transition-colors">← Back to Home</Link>
        </div>
      </motion.div>
    </div>
  );
}
